INSERT INTO `announcements` (`id`, `name`, `to`, `csv`, `cc`, `subject`, `header`, `body`, `footer`, `attachment`, `is_sent`, `is_active`, `created_by`, `people_type`, `created_at`, `updated_at`) VALUES
(1, 'admin', '1', NULL, '64', 'Test Subject', '<p>Date: 21-July-2025</p>', '<p>I am writing to you as I recently received a letter from you informing me that the insurance premium for my car is going to increase from next month.</p>\r\n<p>&nbsp;</p>\r\n<p>&nbsp;</p>\r\n<p>&nbsp;</p>\r\n<p>&nbsp;</p>\r\n<p>As you will be aware if you check my records, I have held my insurance with your company for nearly seven years now. During this time, I have never had an accident and never had any reason to make a claim on my insurance.</p>\r\n<p>I understand that at times prices need to be increased. However, this increase you are suggesting will result in a 20% increase in the amount I pay each month, a rate I feel is too much.</p>\r\n<p>I would therefore like you to write back to me and explain why such an increase has been proposed. If you are unable to justify it to my satisfaction, then I am afraid that I will have no other option but to move my insurance to another company.</p>\r\n<p>I look forward to hearing from you,</p>', '<p>Rehan Mansoor</p>', NULL, 1, 1, 1, 'user', '2025-07-21 16:56:39', '2025-07-23 07:44:15'),
(2, 'rehan new', '1,64', NULL, '1', 'Test Subject 2', '<p>Header</p>', '<p>Body</p>', '<p>Footer</p>', '202507210503251753113607277Screenshot from 2025-04-22 10-58-26.png', 1, 1, 1, 'user', '2025-07-21 17:03:25', '2025-07-23 07:44:35'),
(3, 'rehan tefu', '1,64', NULL, '1', 'Test Subject', '<p>Header</p>', '<p>Body</p>', '<p>Footer</p>', NULL, 1, 1, 1, 'user', '2025-07-22 11:21:39', '2025-07-22 11:22:24'),
(4, 'Roland Mbole', '1,58,60,70,71', NULL, '1', '🎉 Thank You for Voting! 🙌', '<p>MulemaGC</p>', '<p>We sincerely appreciate your incredible support in voting for your favorite contestants in the Mulema Gospel Talent Competition 🎤🇨🇲. Your votes are making a difference! 💥</p>\r\n<p>🌟 Don\'t miss the upcoming Primes:<br />📅 August 9 &ndash; Prime 1<br />📅 August 17 &ndash; Prime 2<br />📅 August 23 &ndash; Prime 3<br />📅 August 30 &ndash; The Grand Prime ✨</p>\r\n<p>Let&rsquo;s keep the fire 🔥 burning and support Gospel talent to the top! 💪💯</p>', '<p>🙏 God bless you richly!<br />#MulemaGospel #VoteAndSupport #GospelTalent #ThankYou</p>', NULL, 1, 1, 1, 'user', '2025-07-22 17:22:28', '2025-07-22 18:38:37'),
(5, 'rehan mansoor', '20250722052903announcement_peopel.csv', NULL, NULL, 'subject', '<p>header</p>', '<p>body</p>', '<p>footer 2</p>', NULL, 1, 1, 1, 'csv', '2025-07-22 17:25:16', '2025-07-22 17:29:03'),
(6, 'Papa Rolly', '58,64', NULL, '1', '🎉 Thank You for Voting! 🙌', '<p>🎉MulemaGC🙌</p>', '<p></p>\r\n<p data-start=\"128\" data-end=\"263\">ulema Gospel Competition (Mulema GC) sincerely appreciates you for taking the time to vote and support your favorite contestant! 🗳️❤️</p>\r\n<p data-start=\"265\" data-end=\"358\">Your vote is a voice of encouragement, and your support is what keeps this vision alive! 🌟👏</p>\r\n<p data-start=\"360\" data-end=\"490\">🙏 Thank you for being part of this incredible journey. Let&rsquo;s keep the fire burning as we move forward to the upcoming <strong data-start=\"479\" data-end=\"489\">Primes</strong>:</p>\r\n<p data-start=\"492\" data-end=\"598\">📅 August 9 &ndash; Prime 1<br data-start=\"513\" data-end=\"516\" />📅 August 17 &ndash; Prime 2<br data-start=\"538\" data-end=\"541\" />📅 August 23 &ndash; Prime 3<br data-start=\"563\" data-end=\"566\" />📅 August 30 &ndash; Grand Finale 🎤🏆</p>', '<p>🎶 Stay connected. Keep voting. Keep believing! 💫<br data-start=\"650\" data-end=\"653\" />#MulemaGC #GospelTalent #ThankYou 💜</p>', NULL, 1, 1, 1, 'user', '2025-07-22 18:45:03', '2025-07-22 18:47:14'),
(7, 'Mbole Roland', '20250722092135list.csv', NULL, NULL, 'Thank You for Voting!', '<p>🎉<strong>Mulema Gospel</strong>🎉</p>', '<p data-start=\"128\" data-end=\"263\">&nbsp;</p>\r\n<p data-start=\"128\" data-end=\"263\">&nbsp;</p>\r\n<p data-start=\"128\" data-end=\"263\">Mulema Gospel Competition (Mulema GC) sincerely appreciates you for taking the time to vote and support your favorite contestant!&nbsp;</p>\r\n<p data-start=\"265\" data-end=\"358\">Your vote is a voice of encouragement, and your support is what keeps this vision alive!&nbsp;</p>\r\n<p data-start=\"360\" data-end=\"490\">Thank you for being part of this incredible journey. Let&rsquo;s keep the fire burning as we move forward to the upcoming</p>\r\n<p data-start=\"360\" data-end=\"490\">&nbsp;</p>\r\n<p data-start=\"360\" data-end=\"490\"><strong data-start=\"479\" data-end=\"489\">Primes</strong>:</p>\r\n<ol>\r\n<li data-start=\"492\" data-end=\"598\">August 9 &ndash; Prime 1</li>\r\n<li data-start=\"492\" data-end=\"598\">August 17 &ndash; Prime 2</li>\r\n<li data-start=\"492\" data-end=\"598\">August 23 &ndash; Prime 3</li>\r\n<li data-start=\"492\" data-end=\"598\">August 30 &ndash; Grand Finale&nbsp;</li>\r\n</ol>\r\n<p>Grab Your Tickets</p>\r\n<p>https://mulemagc.com/tickets/1</p>', '<p>Stay connected. Keep voting. Keep believing! 💫<br data-start=\"650\" data-end=\"653\" />#MulemaGC #GospelTalent #ThankYou 💜</p>', NULL, 1, 1, 1, 'csv', '2025-07-22 21:21:35', '2025-07-22 21:34:32'),
(8, 'Roland Mbole', '59,71,76', NULL, '58', 'Thank You for Voting', '<p>!!<strong>Mulema Gospel!!</strong></p>', '<p data-start=\"78\" data-end=\"207\">Mulema Gospel Competition (Mulema GC) sincerely appreciates you for taking the time to vote and support your favorite contestant.</p>\r\n<p data-start=\"209\" data-end=\"297\">Your vote is a voice of encouragement, and your support is what keeps this vision alive.</p>\r\n<p data-start=\"299\" data-end=\"418\">Thank you for being part of this incredible journey. Let&rsquo;s keep the momentum as we move forward to the upcoming Primes:</p>\r\n<ul data-start=\"420\" data-end=\"517\">\r\n<li data-start=\"420\" data-end=\"442\">\r\n<p data-start=\"422\" data-end=\"442\">August 9 &ndash; Prime 1</p>\r\n</li>\r\n<li data-start=\"443\" data-end=\"466\">\r\n<p data-start=\"445\" data-end=\"466\">August 17 &ndash; Prime 2</p>\r\n</li>\r\n<li data-start=\"467\" data-end=\"490\">\r\n<p data-start=\"469\" data-end=\"490\">August 23 &ndash; Prime 3</p>\r\n</li>\r\n<li data-start=\"491\" data-end=\"517\">\r\n<p data-start=\"493\" data-end=\"517\">August 30 &ndash; Grand Finale</p>\r\n</li>\r\n</ul>\r\n<p data-start=\"519\" data-end=\"599\">&nbsp;</p>', '<p>Stay connected. Keep voting. Keep believing.<br data-start=\"563\" data-end=\"566\" />#MulemaGC #GospelTalent #ThankYou</p>', NULL, 1, 1, 1, 'user', '2025-07-22 21:39:07', '2025-07-22 21:39:22'),
(9, 'Engr. Mbole', '1', NULL, '', 'Help Us Register Your VIP Guests – Submit WhatsApp Numbers Today!', NULL, '<p>We are thrilled to have you in our midst finally. We have been immensely blessed by your God given talents and we want the world to know about you.</p>\r\n<p>However, charity starts at home. In order for you to honour you pastors, leaders and family. We gave you guys free tickets for them. Thank you for the list you gave to us. However, we need to make sure our system works well and that your guests (VIP and family) are well counted, we will need their number via which they will receive a QR code in case they lose their tickets they will be in the system.</p>\r\n<p>Thus, we are asking each of you to write down again the list of your guests with their whatsapp number and they will receive their QR CODE.</p>\r\n<p>The coordinator Roukayatou will collect the physical copies.</p>\r\n<p><br /><br /></p>', '<p>The Mulema Gospel <br />IT Team</p>', NULL, 1, 1, 1, 'user', '2025-08-02 10:15:31', '2025-08-02 10:15:38'),
(10, 'Engr. Mbole', '1,58,59,64,70,71,75,76,77,82,83,84,85,86,87,88,89,90,91,92,93,95,96,97,98,99,100,101,102,103,104,105,106,107,108,109,110,111,112,113,114,115,116,117,118,119,120,121,122,123,124,125,126,127,128,129,130,131,132,133,134,135,136,137,138,139,140,141,142,143,144,145,146,1396,1401', NULL, '1,73,76', '📯 Help Us Register Your VIP Guests – Submit WhatsApp Numbers Today!📯', NULL, '<p>We are thrilled to have you in our midst finally. We have been immensely blessed by your God hiven talents and we want the world to know about you.</p>\r\n<p>However, charity starts at home. In order for you to honour you pastors, leaders and family. We gave you guys free tickets for them. Thank you for the list you gave to us. However, we need to make sure our system works well and that your guests (VIP and family) are well counted, we will need their number via which they will receive a QR code in case they lose their tickets they will be in the system.</p>\r\n<p>Thus, we are asking each of you to write down again the list of your guests with their whatsapp number and they will receive their QR CODE.</p>\r\n<p>The coordinator Roukayatou will collect the physical copies.</p>', '<p>The Mulema Gospel IT Team&nbsp;<br />IT Coordinator<br />📯Roukayatou📯&nbsp;</p>', NULL, 1, 1, 1, 'user', '2025-08-02 10:24:24', '2025-08-02 10:29:45'),
(11, 'Engr. Mbole', '1,58,59,64,70,71,75,76,77,82,83,84,85,86,87,88,89,90,91,92,93,95,96,97,98,99,100,101,102,103,104,105,106,107,108,109,110,111,112,113,114,115,116,117,118,119,120,121,122,123,124,125,126,127,128,129,130,131,132,133,134,135,136,137,138,139,140,141,142,143,144,145,146,1396,1401', NULL, '1,76', 'Aidez-nous à enregistrer vos invités VIP – Soumettez leurs numéros WhatsApp dès aujourd’hui !', NULL, '<p>&nbsp;</p>\r\n<p data-start=\"47\" data-end=\"223\">Nous sommes ravis de vous avoir enfin parmi nous. Nous avons &eacute;t&eacute; immens&eacute;ment b&eacute;nis par les talents que Dieu vous a donn&eacute;s, et nous souhaitons que le monde entier vous d&eacute;couvre.</p>\r\n<p data-start=\"225\" data-end=\"480\">Cependant, la charit&eacute; bien ordonn&eacute;e commence par soi-m&ecirc;me. Pour vous permettre d&rsquo;honorer vos pasteurs, responsables et membres de famille, nous vous avons offert des billets gratuits &agrave; leur intention. Merci pour la liste que vous nous avez d&eacute;j&agrave; transmise.Toutefois, afin d\'assurer le bon fonctionnement de notre syst&egrave;me et de garantir que vos invit&eacute;s (VIP et proches) soient bien pris en compte, nous aurons besoin de leur num&eacute;ro WhatsApp. Gr&acirc;ce &agrave; ce num&eacute;ro, ils recevront un code QR. En cas de perte du billet, ils seront toujours enregistr&eacute;s dans notre syst&egrave;me.</p>\r\n<p data-start=\"792\" data-end=\"958\">Nous vous demandons donc de bien vouloir <strong data-start=\"833\" data-end=\"869\">r&eacute;&eacute;crire la liste de vos invit&eacute;s</strong>, en y ajoutant <strong data-start=\"885\" data-end=\"909\">leur num&eacute;ro WhatsApp</strong>, afin qu&rsquo;ils puissent recevoir leur <strong data-start=\"946\" data-end=\"957\">CODE QR</strong>.</p>\r\n<p data-start=\"792\" data-end=\"958\">&nbsp;</p>\r\n<p data-start=\"792\" data-end=\"958\">La coordinatrice Roukayatou se chargera de collecter les copies physiques.</p>', '<p>Mulema Gospel IT (La coordinatrice Roukayatou)</p>', NULL, 1, 1, 1, 'user', '2025-08-02 10:40:33', '2025-08-02 10:47:35'),
(12, 'Engr. Mbole', '1785,1787', NULL, '', 'Testing of the system', NULL, '<p>WE just wish tot est the system and see if there is somethign wrong with it so that we can do more work.&nbsp;</p>', '<p>Engr. Mbole</p>', NULL, 1, 1, 1, 'customer', '2025-08-02 13:00:27', '2025-08-02 13:00:36'),
(13, 'Engr. Mbole', '1,58,59,64,70,71,75,76,77,82,83,84,85,86,87,88,89,90,91,92,93,95,96,97,98,99,100,101,102,103,104,105,106,107,108,109,110,111,112,113,114,115,116,117,118,119,120,121,122,123,124,125,126,127,128,129,130,131,132,133,134,135,136,137,138,139,140,141,142,143,144,145,146,1396,1401,1785,1787', NULL, '', 'Formulaire d’Invitation des Invités / Guest Invitation Form', NULL, '<p></p>\r\n<h3 data-start=\"156\" data-end=\"210\"></h3>\r\n<h3 data-start=\"129\" data-end=\"154\">✅&nbsp;<strong data-start=\"156\" data-end=\"221\">Please fill in the names and WhatsApp numbers of your guests.</strong><br data-start=\"221\" data-end=\"224\" />If you have 5 guests, kindly complete only 5 entries.<br data-start=\"277\" data-end=\"280\" />If you have more or fewer, simply fill in the exact number of guests you are inviting.<br data-start=\"366\" data-end=\"369\" />👉 <strong data-start=\"372\" data-end=\"426\">Click on the link below to submit the information.</strong></h3>\r\n<h3 data-start=\"129\" data-end=\"154\"><strong data-start=\"372\" data-end=\"426\"><br /><br />https://forms.gle/q39mE8vkfWo2UCzR7<br /></strong></h3>\r\n<hr data-start=\"428\" data-end=\"431\" />\r\n<h3 data-start=\"433\" data-end=\"460\">&nbsp;</h3>\r\n<h3 data-start=\"433\" data-end=\"460\">✅ <strong data-start=\"462\" data-end=\"534\">Veuillez renseigner les noms et les num&eacute;ros WhatsApp de vos invit&eacute;s.</strong><br data-start=\"534\" data-end=\"537\" />Si vous avez 5 invit&eacute;s, veuillez remplir uniquement 5 entr&eacute;es.<br data-start=\"599\" data-end=\"602\" />Si vous en avez plus ou moins, remplissez simplement le nombre exact d&rsquo;invit&eacute;s que vous souhaitez inviter.<br data-start=\"708\" data-end=\"711\" />👉 <strong data-start=\"714\" data-end=\"781\">Cliquez sur le lien ci-dessous pour soumettre les informations.<br /><br /></strong></h3>\r\n<p>&nbsp;</p>\r\n<p data-start=\"462\" data-end=\"781\"><strong data-start=\"714\" data-end=\"781\">https://forms.gle/q39mE8vkfWo2UCzR7</strong></p>', '<p>Mulema Gospel IT</p>\r\n<p>La Coordinatrice</p>\r\n<p>Roukayatou&nbsp;</p>', '202508040240371754314831652Primes.gif', 1, 1, 1, 'user', '2025-08-04 14:40:37', '2025-08-04 14:42:52'),
(14, 'Mbole', '1,58,59,64,70,71,75,76,77,82,83,84,85,86,87,88,89,90,91,92,93,95,96,97,98,99,100,101,102,103,104,105,106,107,108,109,110,111,112,113,114,115,116,117,118,119,120,121,122,123,124,125,126,127,128,129,130,131,132,133,134,135,136,137,138,139,140,141,142,143,144,145,146,1396,1401,1785,1787', NULL, '', 'Dernières heures pour voter – Suspense garanti au Prime 1 🎶🇨🇲', NULL, '<p></p>\r\n<p data-start=\"186\" data-end=\"514\"></p>\r\n<p data-start=\"141\" data-end=\"494\">Voting for this phase will officially close <strong data-start=\"185\" data-end=\"220\">today at exactly 12:00 midnight</strong>. Any votes received after this time will be counted for the next phase of the competition.<br data-start=\"311\" data-end=\"314\" />Le vote pour cette phase se terminera <strong data-start=\"352\" data-end=\"395\">aujourd&rsquo;hui &agrave; exactement 24h00 (minuit)</strong>. Tout vote re&ccedil;u apr&egrave;s cette heure sera pris en compte pour la prochaine phase de la comp&eacute;tition.</p>\r\n<p data-start=\"496\" data-end=\"752\">Please note: Total vote counts will no longer be displayed to maintain suspense and avoid speculation on the results.<br data-start=\"613\" data-end=\"616\" />&Agrave; noter : Le nombre total de votes ne sera plus affich&eacute; afin de maintenir le suspense et d&rsquo;&eacute;viter toute sp&eacute;culation sur les r&eacute;sultats.</p>\r\n<p data-start=\"496\" data-end=\"752\">You are warmly invited to <strong data-start=\"780\" data-end=\"854\">Prime 1 tomorrow at the Palais des Sports Complex, starting at 3:00 PM</strong> &mdash; an unforgettable worship experience where 53 Contestants from across Cameroon will showcase our nation&rsquo;s rich cultural diversity in praise to the Most High.<br data-start=\"1013\" data-end=\"1016\" />Vous &ecirc;tes chaleureusement invit&eacute;s au <strong data-start=\"1053\" data-end=\"1111\">Prime 1 demain au Palais des Sports, &agrave; partir de 15h00</strong> &mdash; un moment inoubliable d&rsquo;adoration o&ugrave; 53 candidats venus des quatre coins du Cameroun pr&eacute;senteront la richesse culturelle de notre nation en louange au Tr&egrave;s-Haut.</p>', '<p><br data-start=\"1325\" data-end=\"1328\" /><em data-start=\"1328\" data-end=\"1363\">Le Coordonnateur IT du Mulema Gospel</em></p>\r\n<p><strong data-start=\"1366\" data-end=\"1379\">Rokayatou</strong></p>', NULL, 1, 1, 1, 'user', '2025-08-08 23:33:45', '2025-08-08 23:35:03'),
