,2318,2319,2320,2321,2322,2323,2324,2325,2326,2327,2328,2329,2330,2331,2332,2333,2334,2335,2336,2339,2340,2341,2342,2343,2344,2345,2346,2347,2348,2349,2350,2351,2352,2353,2356,2361,2362,2363,2364,2365,2366,2369,2370,2371,2372,2373,2374,2375,2376', NULL, '', 'établissement du système de vote – Merci pour votre patience / oting System Restored – Thank You for Your Patience', NULL, '<p></p>\r\n<p data-start=\"249\" data-end=\"382\">Nous vous pr&eacute;sentons nos sinc&egrave;res excuses pour l&rsquo;interruption temporaire de notre syst&egrave;me de vote, due &agrave; une maintenance technique.</p>\r\n<p data-start=\"384\" data-end=\"522\">Nous avons le plaisir de vous informer que le syst&egrave;me est d&eacute;sormais compl&egrave;tement r&eacute;tabli et que vous pouvez &agrave; nouveau voter normalement.</p>\r\n<p data-start=\"524\" data-end=\"613\">Merci pour votre patience et votre compr&eacute;hension, ainsi que pour votre soutien continu.</p>\r\n<p data-start=\"524\" data-end=\"613\">__________________________________________________________________________________________________________________</p>\r\n<p data-start=\"644\" data-end=\"760\">We sincerely apologize for the temporary downtime experienced with our voting system due to essential maintenance.</p>\r\n<p data-start=\"762\" data-end=\"872\">We are pleased to inform you that the system has now been fully restored, and voting can continue as normal.</p>\r\n<p data-start=\"874\" data-end=\"942\">Thank you for your patience, understanding, and continued support.</p>', '<p>Cordialement / Kind regards,</p>\r\n<p><strong data-start=\"975\" data-end=\"988\">Rokayatou</strong></p>\r\n<p>IT Coordinator</p>', NULL, 0, 1, 1, 'customer', '2025-08-12 20:01:07', '2025-08-12 20:01:07'),
(22, 'Engr. Mbole', '1,58,59,64,70,71,75,76,77,82,83,84,85,86,87,88,89,90,91,92,93,95,96,97,98,99,100,101,102,103,104,105,106,107,108,109,110,111,112,113,114,115,116,117,118,119,120,121,122,123,124,125,126,127,128,129,130,131,132,133,134,135,136,137,138,139,140,141,142,143,144,145,146,1396,1401,1785,1787,2058,2060,2065,2067,2068,2315,2337,2338,2354,2355,2357,2358,2359,2360,2367,2368', NULL, '1,58,59,64,70,71,75,76,77,82,83,84,85,86,87,88,89,90,91,92,93,95,96,97,98,99,100,101,102,103,104,105,106,107,108,109,110,111,112,113,114,115,116,117,118,119,120,121,122,123,124,125,126,127,128,129,130,131,132,133,134,135,136,137,138,139,140,141,142,143,144,145,146,1396,1401,1785,1787,2058,2060,2065,2067,2068,2315,2337,2338,2354,2355,2357,2358,2359,2360,2367,2368', 'Rétablissement du système de vote – Merci pour votre patience Subject: Voting System Restored – Thank You for Your Patience', '<p>Mulema Gospel</p>', '<p>&nbsp;</p>\r\n<p data-start=\"249\" data-end=\"382\">Nous vous pr&eacute;sentons nos sinc&egrave;res excuses pour l&rsquo;interruption temporaire de notre syst&egrave;me de vote, due &agrave; une maintenance technique.</p>\r\n<p data-start=\"384\" data-end=\"522\">Nous avons le plaisir de vous informer que le syst&egrave;me est d&eacute;sormais compl&egrave;tement r&eacute;tabli et que vous pouvez &agrave; nouveau voter normalement.</p>\r\n<p data-start=\"524\" data-end=\"613\">Merci pour votre patience et votre compr&eacute;hension, ainsi que pour votre soutien continu.</p>\r\n<p data-start=\"524\" data-end=\"613\">⭐⭐⭐⭐⭐⭐⭐⭐⭐⭐⭐⭐⭐⭐⭐⭐⭐⭐⭐⭐⭐⭐⭐</p>\r\n<p data-start=\"644\" data-end=\"760\">We sincerely apologize for the temporary downtime experienced with our voting system due to essential maintenance.</p>\r\n<p data-start=\"762\" data-end=\"872\">We are pleased to inform you that the system has now been fully restored, and voting can continue as normal.</p>\r\n<p data-start=\"874\" data-end=\"942\">Thank you for your patience, understanding, and continued support.</p>', '<p>Cordialement</p>\r\n<p><br data-start=\"934\" data-end=\"937\" /><strong data-start=\"937\" data-end=\"950\">Rokayatou</strong></p>\r\n<p><br data-start=\"950\" data-end=\"953\" />IT Coordinator</p>\r\n<p>Mulema Gospel</p>', '20250812081348175502593977211111.jpeg', 0, 1, 1, 'user', '2025-08-12 20:13:48', '2025-08-12 20:13:48'),
(23, 'Engr. Mbole', '20250812081849Staff_List.csv', NULL, NULL, '📢 Extraordinary Online Meeting on the Return Match Versus Acha Hospital Annex Bamenda📢', NULL, '<p><strong>Pending letter</strong></p>\r\n<p>&nbsp;</p>\r\n<p>Following our recent announcement regarding the return leg of our football match against Acha Hospital Annex Bamenda scheduled for <strong>Saturday, 16th August 2025</strong>, it is imperative that we assess our current financial standing before confirming the fixture.</p>\r\n<p>I am therefore convening an <strong>Extraordinary Online EXCO Meeting</strong> on <strong>Wednesday, 13th August 2025, from 7:00 PM to 8:00 PM</strong> via Google Meet.</p>\r\n<p>🔗<strong> Meeting Link:</strong> <a href=\"https://meet.google.com/myy-ixki-gzy\">https://meet.google.com/myy-ixki-gzy</a></p>\r\n<p>&nbsp;</p>\r\n<p><strong>Agenda:</strong></p>\r\n<ol>\r\n<li><strong>Review of contributions received so far.</strong></li>\r\n<li><strong>Analysis of whether the available funds meet the budgeted requirement of 200,000 FCFA.</strong></li>\r\n<li><strong>Decision on whether to proceed with or postpone the scheduled match.</strong></li>\r\n<li><strong>Any other business.</strong><strong><br /></strong>Your punctual attendance and active participation are critical to ensuring that our decision reflects both our financial realities and the club&rsquo;s long-term interests.</li>\r\n</ol>\r\n<p>Thank you for your dedication and continued commitment to Nkwen Baptist Center FC.</p>\r\n<p>&nbsp;</p>\r\n<p>&nbsp;</p>\r\n<p>&nbsp;</p>\r\n<p>Best Regards</p>\r\n<p>Tefu R. Mbole</p>\r\n<p>N.B.C Football Club</p>\r\n<p>CC: Mr. Suiyka Enoch, Mr. Methuselah&nbsp;</p>', NULL, NULL, 0, 1, 1, 'csv', '2025-08-12 20:18:49', '2025-08-12 20:19:30'),
(24, 'Engr. Mbole', '1,58,59,64,70,71,75,76,77,82,83,84,85,86,87,88,89,90,91,92,93,95,96,97,98,99,100,101,102,103,104,105,106,107,108,109,110,111,112,113,114,115,116,117,118,119,120,121,122,123,124,125,126,127,128,129,130,131,132,133,134,135,136,137,138,139,140,141,142,143,144,145,146,1396,1401,1785,1787,2058,2060,2065,2067,2068,2315,2337,2338,2354,2355,2357,2358,2359,2360,2367,2368,2485,2486', NULL, '', 'Mulema Gospel Competition – A Big Thank You and This Sunday’s Scoring Breakdown', NULL, '<p>We want to sincerely thank you for being part of the Mulema Gospel Competition. Your talent, dedication, and passion for sharing the Gospel through music have truly blessed this journey so far.</p>\r\n<p>As we look forward to this Sunday&rsquo;s event, here&rsquo;s how the scoring will be done:</p>\r\n<ul>\r\n<li><strong>Votes:</strong> 10%</li>\r\n<li><strong>Jury Members:</strong> 60%</li>\r\n<li><strong>Ambassadors:</strong> 30%</li>\r\n</ul>\r\n<p>Every note you sing and every moment you share on stage is an opportunity to inspire and touch lives. Give it your best, stay confident, and let your light shine. 🌟</p>\r\n<p>We can&rsquo;t wait to see you lift hearts in worship and celebrate the gift God has given you.</p>\r\n<p>With appreciation,</p>', '<p><strong>Roukayatou</strong></p>\r\n<p>IT Coordinator &ndash;</p>\r\n<p>Mulema Gospel Competition</p>', NULL, 1, 1, 1, 'user', '2025-08-15 20:14:36', '2025-08-15 20:15:45'),
(25, 'asdf a', '60,2660', NULL, '', 'Thanks Bro', NULL, '<p>Happy to meet you brother</p>', '<p>Papa Rolly</p>\r\n<p>Beyond&nbsp;</p>', '202508150827371755286016811DOWN SCALED.png', 1, 1, 1, 'customer', '2025-08-15 20:27:37', '2025-08-15 20:27:48'),
(26, 'Engr. Mbole', '70,71,76,77,82,83,84,85,86,87,88,89,90,91,92,93,95,96,97,98,99,100,101,102,103,104,105,106,107,108,109,110,111,112,113,114,115,116,117,118,119,120,121,122,123,124,125,126,127,128,129,130,131,132,133,134,135,136,137,138,139,140,141,142,143,144,1396,1785,1787,2058,2060,2065,2067,2068,2315,2337,2338,2354,2355,2357,2358,2359,2360,2367,2368,2485', NULL, '59', 'Compétition Mulema Gospel – Remerciements et Informations pour ce Dimanche 🎶✨', '<p>&nbsp;</p>\r\n<p data-start=\"193\" data-end=\"335\">Merci d&rsquo;&ecirc;tre partie prenante de la Comp&eacute;tition Mulema Gospel. Votre talent et votre passion pour l&rsquo;adoration sont une b&eacute;n&eacute;diction pour tous.</p>\r\n<p data-start=\"337\" data-end=\"395\">Ce dimanche, la r&eacute;partition des notes sera la suivante :</p>\r\n<ul data-start=\"396\" data-end=\"461\">\r\n<li data-start=\"396\" data-end=\"415\">\r\n<p data-start=\"398\" data-end=\"415\"><strong data-start=\"398\" data-end=\"409\">Votes :</strong> 10%</p>\r\n</li>\r\n<li data-start=\"416\" data-end=\"434\">\r\n<p data-start=\"418\" data-end=\"434\"><strong data-start=\"418\" data-end=\"428\">Jury :</strong> 60%</p>\r\n</li>\r\n<li data-start=\"435\" data-end=\"461\">\r\n<p data-start=\"437\" data-end=\"461\"><strong data-start=\"437\" data-end=\"455\">Ambassadeurs :</strong> 30%</p>\r\n</li>\r\n</ul>\r\n<p data-start=\"463\" data-end=\"589\">Venez briller sur sc&egrave;ne et partager la gr&acirc;ce de Dieu. <strong data-start=\"517\" data-end=\"542\">L&rsquo;entr&eacute;e est gratuite</strong> &ndash; invitez vos proches &agrave; venir vous soutenir.</p>\r\n<p data-start=\"591\" data-end=\"685\">Avec toute ma consid&eacute;ration,<br data-start=\"619\" data-end=\"622\" /><br /></p>', '<p><strong data-start=\"622\" data-end=\"636\">Roukayatou</strong></p>\r\n<p>Coordinatrice IT&nbsp;</p>\r\n<p>Comp&eacute;tition Mulema Gospel</p>', NULL, NULL, 1, 1, 1, 'user', '2025-08-15 20:50:07', '2025-08-15 20:53:59'),
