,3130,3131,3132,3133,3134,3135,3136,3137,3138,3139,3140,3141,3142,3143', NULL, '', 'Voting Closed – Will Resume After Prime 3 at Midnight (Objet : Arrêt des votes – Reprise après Prime 3 à minuit)', '<p>MULEMA GOSPEL PRIME 3</p>', '<p></p>\r\n<p data-start=\"212\" data-end=\"331\">Please be informed that <strong data-start=\"236\" data-end=\"262\">voting has now stopped</strong> on the platform. Voting will <strong data-start=\"292\" data-end=\"328\">resume at midnight after Prime 3</strong>.</p>\r\n<p data-start=\"333\" data-end=\"446\">We sincerely thank you for your participation and encourage you to stay connected as the competition continues.</p>\r\n<p data-start=\"333\" data-end=\"446\">&nbsp;</p>\r\n<p data-start=\"333\" data-end=\"446\"></p>\r\n<p data-start=\"658\" data-end=\"802\">Nous vous informons que <strong data-start=\"682\" data-end=\"718\">les votes sont d&eacute;sormais arr&ecirc;t&eacute;s</strong> sur la plateforme. Le processus de vote <strong data-start=\"759\" data-end=\"799\">reprendra &agrave; minuit, apr&egrave;s le Prime 3</strong>.</p>\r\n<p data-start=\"804\" data-end=\"941\">Nous vous remercions sinc&egrave;rement pour votre participation et vous encourageons &agrave; rester connect&eacute;s alors que la comp&eacute;tition se poursuit.</p>', '<p>Cordialement,</p>\r\n<p><strong data-start=\"959\" data-end=\"973\">Roukayatou</strong></p>\r\n<p>Coordinatrice IT</p>\r\n<p><em data-start=\"995\" data-end=\"1028\">Mulema Gospel Talent &ndash; Saison 1</em></p>', NULL, 0, 1, 1, 'customer', '2025-08-23 12:39:00', '2025-08-23 12:39:00'),
(36, 'Engr. Mbole', '76,2065,2315,2337,2354,2355,2357,2358,2359,2360', NULL, '1,59', 'Important: Access Your Account Before Prime 3 (Objet : Important : Accédez à votre compte avant le Prime 3)', '<p>MULEMA GOSPEL PRIME 3</p>', '<p>&nbsp;</p>\r\n<p data-start=\"228\" data-end=\"388\">ENGLISH!</p>\r\n<p data-start=\"228\" data-end=\"388\">Please ensure you are able to log into your account before Prime 3 begins.</p>\r\n<p data-start=\"228\" data-end=\"388\">The voting platform has now closed, and the system is open exclusively for grading.</p>\r\n<p data-start=\"228\" data-end=\"388\">To make your work easier, only the contestants&rsquo; names are visible in the <em data-start=\"463\" data-end=\"481\">Awaiting Grading</em> menu.</p>\r\n<p data-start=\"228\" data-end=\"388\">Your contribution to Mulema is invaluable and deeply appreciated.</p>\r\n<p data-start=\"228\" data-end=\"388\">&nbsp;</p>\r\n<p data-start=\"228\" data-end=\"388\">FRENCH!</p>\r\n<p data-start=\"228\" data-end=\"388\">&nbsp;</p>\r\n<p data-start=\"465\" data-end=\"641\">&nbsp;</p>\r\n<p data-start=\"465\" data-end=\"641\">Veuillez vous assurer que vous pouvez vous connecter &agrave; votre compte avant le d&eacute;but du Prime 3.</p>\r\n<p data-start=\"465\" data-end=\"641\">La plateforme de vote est d&eacute;sormais ferm&eacute;e et le syst&egrave;me est ouvert exclusivement pour la notation</p>\r\n<p data-start=\"465\" data-end=\"641\">Pour faciliter votre travail, seuls les noms des candidats sont visibles dans le menu <em data-start=\"551\" data-end=\"575\">En Attente de Notation</em>.</p>\r\n<p data-start=\"465\" data-end=\"641\">Votre contribution &agrave; Mulema est inestimable et tr&egrave;s appr&eacute;ci&eacute;e.</p>', '<p>Bien cordialement,</p>\r\n<p><br data-start=\"661\" data-end=\"664\" /><strong data-start=\"664\" data-end=\"678\">Roukayatou</strong></p>\r\n<p><br data-start=\"678\" data-end=\"681\" />Coordinatrice IT, Mulema</p>', NULL, 1, 1, 1, 'user', '2025-08-23 13:17:56', '2025-08-23 13:19:27'),
